mapper.select:
SELECT ar.approval_id, ar.request_type_code, ar.requester_admin_id, req.name AS requester_name, ar.target_id, ar.status_code, ar.requested_at, ar.completed_at, CASE ar.request_type_code WHEN 'CARD_PUBLISH' THEN c.card_name WHEN 'CARD_UPDATE' THEN c.card_name WHEN 'TERMS_PUBLISH'THEN tm.title ELSE NULL END AS target_name, al.approval_line_id, al.approval_id AS line_approval_id, al.approver_admin_id, apv.name AS approver_name, al.approval_order, al.status_code AS line_status_code, al.comment_text, al.approved_at FROM APPROVAL_REQUESTS ar LEFT JOIN ADMIN_USERS req ON ar.requester_admin_id = req.admin_id LEFT JOIN APPROVAL_LINES al ON ar.approval_id = al.approval_id LEFT JOIN ADMIN_USERS apv ON al.approver_admin_id = apv.admin_id LEFT JOIN CARD_VERSIONS cv ON ar.target_id = cv.version_id AND ar.request_type_code IN ('CARD_PUBLISH','CARD_UPDATE') LEFT JOIN CARDS c ON cv.card_id = c.card_id LEFT JOIN TERMS t ON ar.target_id = t.terms_id AND ar.request_type_code = 'TERMS_PUBLISH' LEFT JOIN TERMS_MASTERS tm ON t.terms_master_id = tm.terms_master_id WHERE 1 = 1
AND ar.approval_id IN ( SELECT approval_id FROM APPROVAL_LINES WHERE approver_admin_id = #{approverAdminId} )
AND ar.status_code = #{statusCode}
AND ar.request_type_code = #{requestTypeCode}
ORDER BY ar.requested_at DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(DISTINCT ar.approval_id)
FROM APPROVAL_REQUESTS ar
LEFT JOIN APPROVAL_LINES al ON ar.approval_id = al.approval_id
WHERE 1 = 1

    AND ar.approval_id IN (
        SELECT approval_id FROM APPROVAL_LINES
        WHERE  approver_admin_id = #{approverAdminId}
    )


    AND ar.status_code = #{statusCode}


    AND ar.request_type_code = #{requestTypeCode}

